SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vr_nsk_015_009000 (membership_no, deposit_account_no, deposit_account_name, fixed_due_status, interest_paid, operate_date, principal, new_prin, deposit_type_code, deposit_name) AS SELECT sc_dep_m_creditor.membership_no,
         sc_dep_m_creditor.deposit_account_no,   
         sc_dep_m_creditor.deposit_account_name,   
         sc_dep_m_interest_paid.fixed_due_status,   
         sc_dep_m_interest_paid.interest_paid,   
         sc_dep_m_interest_paid.operate_date,   
         sc_dep_m_interest_paid.principal, 
         CASE WHEN   sc_dep_m_interest_paid.fixed_due_status ='D' THEN ( sc_dep_m_interest_paid.principal  + sc_dep_m_interest_paid.interest_paid  - sc_dep_m_interest_paid.tax_paid  )    ELSE sc_dep_m_interest_paid.principal END   as new_prin ,  
         sc_dep_m_creditor.deposit_type_code,  
         sc_dep_m_rule.deposit_name 
    FROM sc_dep_m_creditor,   
         sc_dep_m_rule,   
         sc_dep_m_interest_paid  
   WHERE ( sc_dep_m_creditor.deposit_type_code = sc_dep_m_rule.deposit_type_code ) and ( sc_dep_m_creditor.deposit_account_no = sc_dep_m_interest_paid.deposit_account_no ) and ( sc_dep_m_interest_paid.tax_paid > 0 ) and ( sc_dep_m_rule.invest_status = '0' ) 
--and sc_dep_m_interest_paid.operate_date between '1/11/2024' and '31/12/2024'   
 
ORDER BY sc_dep_m_creditor.deposit_account_no ASC,   
         sc_dep_m_interest_paid.operate_date ASC;

